INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 2, 0, 1, "vo_minigame_1012_result_1040", 3.58, 8, 1, "あんたの点数は～～…\n…はい！　０てーん！！\n…って、ふざけんなーー！！！", 2, 0, 11300141, 3001);
