INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 1, 20, 1, "vo_minigame_1012_result_1045", 3.74, 7, 2, "はい、よくできました！\n基礎はもう完璧ね！\n次はもっと難しい問題にも\nチャレンジしちゃいなさいよ！", 1, 10, 12300101, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 1, 20, 1, "vo_minigame_1012_result_1046", 3.85, 1, 2, "なによあんた、走り出したペンが\n止まらないって感じ？\nったくシンプルにすごいじゃない\n花丸あげるわ！", 9, 0, 12300102, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 1, 20, 1, "vo_minigame_1012_result_1047", 0.01, 5, 2, "すごい点数ね…！\nあんた勉強してないとか言って\nホントはめちゃくちゃやってる\nパターンのやつね！？", 5, 8, 12300103, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 2, 20, 1, "vo_minigame_1012_result_1048", 2.86, 8, 2, "勉強の成果、\nちゃんとでてんじゃない！\nあたしもあんたの先生として、\n鼻が高いわ～♪", 7, 4, 12300104, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 2, 20, 1, "vo_minigame_1012_result_1049", 2.02, 5, 2, "オッケー！　もう十分よ！\nこれ以上でき過ぎちゃったら、\nあたしが教える必要なくなるわ！", 3, 9, 12300105, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 2, 20, 1, "vo_minigame_1012_result_1050", 4.46, 5, 2, "難しい問題を選んだつもりなのに\nすごい正解数ね…！\nでもまだ上がある…\n次は最難関に挑戦よ！", 1, 0, 12300106, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 3, 20, 1, "vo_minigame_1012_result_1051", 6.85, 5, 2, "すごいすごいとは思ってたけど、\nあんた勉強も完璧なの…？\nそりゃみんなあんたに惚れ…\nや、な、なんでもない！！", 4, 7, 12300107, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 3, 20, 1, "vo_minigame_1012_result_1052", 3.79, 5, 2, "この問題、あたしでも悩む\n超難問なのに…\nふふっ、もう褒めるしかないわ！\n大変よくできました！", 9, 0, 12300108, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 3, 20, 1, "vo_minigame_1012_result_1053", 0.01, 4, 2, "別に顔赤くなんてなってない！\n頭がいい人が好きとか…\nかっこいいとか…\n…思ってないからね！", 4, 7, 12300109, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 1, 20, 1, "vo_minigame_1012_result_1054", 0.0, 5, 2, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 5, 0, 12300110, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 2, 20, 1, "vo_minigame_1012_result_1054", 0.0, 5, 2, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 5, 0, 12300112, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (-1, 3, 20, 1, "vo_minigame_1012_result_1054", 0.0, 5, 2, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 5, 0, 12300114, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (19, 1, 15, 1, "vo_minigame_1012_result_1056", 3.0, 5, 2, "おお～かなり正解できてるわね！\nこの調子でもっとすごい点\n目指しちゃうわよ！", 7, 10, 12300116, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (19, 1, 15, 1, "vo_minigame_1012_result_1057", 0.01, 8, 2, "うん、バッチリいい感じよ！\nちゃんと勉強してるみたいで\n関心関心♪", 8, 10, 12300117, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (19, 1, 15, 1, "vo_minigame_1012_result_1058", 4.01, 5, 2, "え、こんなにいい点取れたのに\nまだ満足してないの？\nなによその向上心…\nいいじゃない！", 8, 0, 12300118, 3001);
