INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (19, 2, 15, 1, "vo_minigame_1012_result_1060", 0.0, 10, 2, "この難易度でも\nスラスラ答えちゃうなんて…\nあんたって\nほんとすごいやつよね…！", 10, 0, 12300120, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (19, 2, 15, 1, "vo_minigame_1012_result_1061", 3.66, 8, 2, "これだけ正解できたら\n勉強も楽しいわよね♪\nさ、まだまだ続けるわよ～！", 7, 4, 12300121, 3001);
