INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (19, 3, 15, 1, "vo_minigame_1012_result_1063", 2.7, 8, 2, "すごい！　とってもいい成績よ！\nこの難問も、あんたにかかりゃ\nイチコロってやつ？", 1, 0, 12300123, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (19, 3, 15, 1, "vo_minigame_1012_result_1064", 3.98, 5, 2, "あんた…もしかして\nあたしより点数いいかも？\nあ、あたしもあんたを見習って\n勉強しないとね…！", 9, 9, 12300124, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 1, 10, 1, "vo_minigame_1012_result_1067", 2.51, 7, 2, "うん、なかなかいい点数よ！\nでもまだまだ頑張れるわよね？\nはい、次いきましょ！", 1, 0, 12300131, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 1, 10, 1, "vo_minigame_1012_result_1068", 4.16, 1, 2, "十分優秀な成績だけど\nあんたならもっとできる！\nさ、頑張って勉強するわよ！", 7, 0, 12300132, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 1, 10, 1, "vo_minigame_1012_result_1069", 2.07, 8, 2, "うん、いい感じね！\nこの調子で少しずつ、\n正解数を増やしてくわよ！", 7, 0, 12300133, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 2, 10, 1, "vo_minigame_1012_result_1070", 3.51, 8, 2, "難問揃いなのに、\nけっこーいい感じじゃない！\nちゃんとできてるから\n自信もっていいわよ！", 1, 0, 12300134, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 2, 10, 1, "vo_minigame_1012_result_1071", 0.0, 1, 2, "難しい問題でも基礎は大事よ！\nこの調子でどんどん\n点数上げていきましょう！", 1, 0, 12300135, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 2, 10, 1, "vo_minigame_1012_result_1072", 4.3, 1, 2, "10問以上取れてるわね！\nえ、まだ物足りない？\nフフ、じゃあもっと上\n目指しちゃう？", 7, 0, 12300136, 3001);
