INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 2, 10, 1, "vo_minigame_1012_result_1077", 6.58, 1, 2, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 8, 0, 12300143, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (14, 3, 10, 1, "vo_minigame_1012_result_1077", 6.58, 1, 2, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 8, 0, 12300145, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 1, 5, 1, "vo_minigame_1012_result_1078", 4.24, 1, 2, "ふ～ん、まあまあの出来だわ\n悪くはないんだけど…あんたには\nもっともっと期待してるわ～", 7, 0, 12300146, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 1, 5, 1, "vo_minigame_1012_result_1079", 4.74, 7, 2, "うん、頑張ったけど…\n正直もっと正解できるかもね～？\nこんなのあんたには通過点！\nさらに良い点目指してみない？", 1, 0, 12300147, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 1, 5, 1, "vo_minigame_1012_result_1080", 0.0, 1, 2, "まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！", 1, 0, 12300148, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 2, 5, 1, "vo_minigame_1012_result_1081", 2.21, 8, 2, "うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！", 1, 0, 12300149, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 2, 5, 1, "vo_minigame_1012_result_1082", 2.46, 3, 2, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", 1, 0, 12300150, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 2, 5, 1, "vo_minigame_1012_result_1083", 2.94, 3, 2, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", 1, 0, 12300151, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 3, 5, 1, "vo_minigame_1012_result_1084", 4.19, 7, 2, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 1, 0, 12300152, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 3, 5, 1, "vo_minigame_1012_result_1085", 0.0, 1, 2, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 1, 0, 12300153, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 3, 5, 1, "vo_minigame_1012_result_1086", 2.63, 3, 2, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 1, 0, 12300154, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 1, 1, 1, "vo_minigame_1012_result_1087", 5.53, 3, 2, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", 1, 0, 12300155, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 1, 1, 1, "vo_minigame_1012_result_1088", 0.01, 3, 2, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 3, 9, 12300156, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 1, 1, 1, "vo_minigame_1012_result_1089", 4.15, 3, 2, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 1, 3, 12300157, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 2, 1, 1, "vo_minigame_1012_result_1090", 0.01, 9, 2, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 9, 9, 12300158, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 2, 1, 1, "vo_minigame_1012_result_1091", 5.37, 3, 2, "あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！", 1, 0, 12300159, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 2, 1, 1, "vo_minigame_1012_result_1092", 1.44, 3, 2, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 1, 0, 12300160, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 3, 1, 1, "vo_minigame_1012_result_1093", 0.0, 3, 2, "んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？", 3, 0, 12300161, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 3, 1, 1, "vo_minigame_1012_result_1094", 2.91, 3, 2, "…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！", 9, 3, 12300162, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 3, 1, 1, "vo_minigame_1012_result_1095", 2.61, 5, 2, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！", 1, 0, 12300163, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 1, "vo_minigame_1012_result_1096", 3.63, 4, 2, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！", 2, 1, 12300164, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 1, "vo_minigame_1012_result_1097", 4.16, 6, 2, "はあ…自分で何点取ったか\n分かってるわよね～…？\n０点よ０点！　舐めてんの！？", 2, 1, 12300165, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 1, "vo_minigame_1012_result_1098", 0.01, 3, 2, "うう～頭痛い…\nあんたのせいよ！\nなに０点って！\nはあ、このままじゃ赤点よ～…", 3, 6, 12300166, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 2, 0, 1, "vo_minigame_1012_result_1099", 5.75, 6, 2, "ねえ、あんた本気でやったの？\nまさか適当にやるわけないわよね\n…分かった、\nもう一回チャレンジするのよ！", 2, 0, 12300167, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 2, 0, 1, "vo_minigame_1012_result_1100", 5.64, 4, 2, "あ…あんた、０点よ０点…！\nあたしの教え方が悪かった…？\n…燃えてきたわ！\n絶対あんたの学力上げてやる！", 2, 1, 12300168, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 2, 0, 1, "vo_minigame_1012_result_1101", 5.73, 8, 2, "ちょっと待って採点ミスかも…\n…いや合ってるわね。はい０点\n…って０点！？\nふざけんなーー！", 4, 8, 12300169, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 3, 0, 1, "vo_minigame_1012_result_1102", 5.32, 5, 2, "あらら…０点よ\nま、難しい問題だしね…\n…つっても０点は無いわ！\n一問くらい正解しなさいよ！", 3, 1, 12300170, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 3, 0, 1, "vo_minigame_1012_result_1103", 2.37, 3, 2, "残念だけど０点よ\nま、まあ前向きにとらえるなら、\n今が底よ！　どん底！\nあとは上がってくだけね！", 9, 9, 12300171, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 3, 0, 1, "vo_minigame_1012_result_1104", 4.25, 9, 2, "…かなり出来が悪いわね\n一旦休憩しましょうか？\nリフレッシュして頭切り替えて\nもう一度頑張りましょう！", 1, 3, 12300172, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 0, 0, 1, "vo_minigame_1012_gamestart_100", 0.0, 7, 3, "さ、勉強を始めるわよ", 7, 0, 13100101, 1001);
