INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (10, 3, 10, 2, "vo_minigame_1012_result_2006", 6.64, 2, 1, "ヒデサイ、満点パーフェクト！\nこれで、もーサイツヨだね！\nそれっ、ハイタッチ～！", 3, 11, 21300107, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (10, 3, 10, 2, "vo_minigame_1012_result_2007", 0.0, 6, 1, "カンペキ過ぎて\nまぶしぃんですけど！\n〇しかないってどゆこと！？", 6, 0, 21300108, 3001);
