INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6, 1, 4, 2, "vo_minigame_1012_result_2018", 0.92, 6, 1, "お！　あと半分だし\nうちも、もうちっと\nがんばってみるね！", 0, 0, 21300119, 3001);
