INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6, 2, 4, 2, "vo_minigame_1012_result_2021", 2.13, 0, 1, "これで半分ぐらい？\nよしっ、とりま赤点回避！\nやりー！", 2, 0, 21300122, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6, 2, 4, 2, "vo_minigame_1012_result_2022", 2.38, 0, 1, "あともう半分だね！\nフレッフレッ、ヒデサイ！\nうちもがんばる～！", 2, 0, 21300123, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6, 2, 4, 2, "vo_minigame_1012_result_2023", 3.5, 4, 1, "う～ん、やっぱムズいね\nでも、半分ぐらい〇だし\nイケそーな気するね！", 0, 0, 21300124, 3001);
