INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6, 3, 4, 2, "vo_minigame_1012_result_2025", 2.14, 3, 1, "やるじゃんヒデサイ！\nえ？　もっと上目指すの？\nじゃあうちもがんばる！", 6, 0, 21300126, 3001);
