INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3, 1, 1, 2, "vo_minigame_1012_result_2027", 2.53, 4, 1, "おにムズだったね～\n…え？　これって簡単なの？\nえへへ、うそだ～？", 10, 5, 21300128, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3, 1, 1, 2, "vo_minigame_1012_result_2028", 0.01, 4, 1, "…ねーねー、ヒデサイ\nうちに合わせて\n悪い点取らなくていいんだよ？", 4, 9, 21300129, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3, 1, 1, 2, "vo_minigame_1012_result_2029", 2.93, 0, 1, "ウォーミングアップは\nこんなところで…\nヒデサイ、次は\n本気出しちゃおうよ！", 3, 0, 21300130, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3, 2, 1, 2, "vo_minigame_1012_result_2030", 4.26, 0, 1, "あ、ヒデサイ\nうちと点数おそろじゃん！\n一緒に赤点取っちゃおっか～♪", 3, 4, 21300131, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3, 2, 1, 2, "vo_minigame_1012_result_2031", 0.0, 10, 1, "えーっと…\nもっかい教えてくれたら\n次はもうちょい\nイケる気するよっ！", 10, 0, 21300132, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3, 2, 1, 2, "vo_minigame_1012_result_2032", 4.98, 9, 1, "うちもさっぱりだった～\nどこ間違えたんだろ…？\nもっかいベンキョーしてみる？", 0, 5, 21300133, 3001);
