INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3, 3, 1, 2, "vo_minigame_1012_result_2034", 0.01, 4, 1, "赤点って感じ？\nう～ん…せっかくだし\nうちと一緒にがんばろ！", 4, 6, 21300135, 3001);
