INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 2, "vo_minigame_1012_result_2036", 2.54, 0, 1, "よし、結果は…\nって０ってマ！？\nヒデサイ、どーしちゃったの？", 6, 0, 21300137, 3001);
