INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 2, "vo_minigame_1012_result_2038", 3.41, 6, 1, "ヒデサイ、０点だね…\nうちが代わりに\nベンキョー教えてあげよっか…？", 4, 0, 21300139, 3001);
