INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 2, 5, 2, "vo_minigame_1012_result_2082", 4.68, 10, 2, "問題ムズいし、この点数は\nありよりのありっしょ？\nえ、もっとできた感じ？", 6, 0, 22300150, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 2, 5, 2, "vo_minigame_1012_result_2083", 0.0, 9, 2, "どこ間違ったんだろ？\nうちさっぱりだった…\nやっぱムズいだけあるね", 9, 0, 22300151, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 3, 5, 2, "vo_minigame_1012_result_2084", 3.55, 0, 2, "激ムズだけど\nやることは一緒だよね？\nうちもヒデサイについてくから\nコツコツがんばろ！", 3, 0, 22300152, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 3, 5, 2, "vo_minigame_1012_result_2085", 2.51, 4, 2, "やっぱおにムズだね…\nそだ、迷ったら\nヒント使うのも\nありよりのあり？", 6, 0, 22300153, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (9, 3, 5, 2, "vo_minigame_1012_result_2086", 6.15, 9, 2, "やっぱテストって\nなんとなくじゃ無理？\n覚えるしかないの？\nじゃあがんばるしかないね…", 5, 0, 22300154, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 1, 1, 2, "vo_minigame_1012_result_2087", 4.12, 4, 2, "できたと思ったけど\nそーじゃなかった系？\nテストってマジきびしー…", 9, 6, 22300155, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 1, 1, 2, "vo_minigame_1012_result_2088", 0.01, 4, 2, "うーん…さっぱり！\nでも簡単な問題なんだよね…？\nもっかいやってみる？", 4, 6, 22300156, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 1, 1, 2, "vo_minigame_1012_result_2089", 5.28, 0, 2, "うちらまだまだ\nベンキョーちうだし…\nこれからだよねっ？\nね、ヒデサイ！", 3, 0, 22300157, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 2, 1, 2, "vo_minigame_1012_result_2090", 2.89, 0, 2, "ちょっとずつ覚えれば\nおーけーっしょ！\nうちと一緒に\nベンキョーだね！", 3, 0, 22300158, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 2, 1, 2, "vo_minigame_1012_result_2091", 5.45, 0, 2, "うちベンキョー苦手でも\nヒデサイとベンキョー\nするのは好き！　だから\nもっかい教えてくれる？", 7, 0, 22300159, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 2, 1, 2, "vo_minigame_1012_result_2092", 4.29, 4, 2, "覚えても、すぐ忘れるんだけど\nどしたらいい？\nあ、そーゆうとき\nフクシューする感じ？", 10, 3, 22300160, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 3, 1, 2, "vo_minigame_1012_result_2093", 4.64, 4, 2, "ムズ過ぎ！\n頭パンクするかと思った…！\nヒデサイ、うちの頭\nふぅふぅして～", 8, 6, 22300161, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 3, 1, 2, "vo_minigame_1012_result_2094", 3.14, 9, 2, "おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！", 5, 0, 22300162, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4, 3, 1, 2, "vo_minigame_1012_result_2095", 6.59, 7, 2, "ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？", 4, 0, 22300163, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 2, "vo_minigame_1012_result_2096", 0.0, 3, 2, "…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！", 3, 0, 22300164, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 2, "vo_minigame_1012_result_2097", 2.2, 9, 2, "０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？", 10, 5, 22300165, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 1, 0, 2, "vo_minigame_1012_result_2098", 0.01, 4, 2, "考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？", 4, 6, 22300166, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 2, 0, 2, "vo_minigame_1012_result_2099", 2.8, 6, 2, "え、ヒデサイも０点？\nじゃあうちと一緒じゃん♪\nまあ焦んないで\nベンキョーしてこーよ！", 2, 3, 22300167, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 2, 0, 2, "vo_minigame_1012_result_2100", 3.22, 9, 2, "むむむ～…０点…！\n覚えてもすぐ忘れちゃうし\nベンキョーってマジ大変", 4, 6, 22300168, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 2, 0, 2, "vo_minigame_1012_result_2101", 2.1, 4, 2, "０点だね…\nでも、へーきへーき\nリベンジしたら、結果オーライ！", 0, 11, 22300169, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 3, 0, 2, "vo_minigame_1012_result_2102", 2.74, 0, 2, "おやつ休憩して\nリベンジしよっ！\n甘いの食べたら、イケるっしょ！", 2, 3, 22300170, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 3, 0, 2, "vo_minigame_1012_result_2103", 3.0, 6, 2, "ヒデサイでも\nおにムズな感じ？\nじゃあ、このテスト\n誰も解けなくない？", 9, 9, 22300171, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 3, 0, 2, "vo_minigame_1012_result_2104", 4.37, 10, 2, "…あれ？\n０が〇に見えてきた！\nきゃはっ、ちょっち\nやる気出てきたかも！", 2, 0, 22300172, 3001);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0, 0, 0, 2, "vo_minigame_1012_gamestart_200", 0.01, 0, 3, "よーし、がんばるぞー", 0, 10, 23100101, 1001);
